var COURSE_PL_ID = [{day: 1, title: `Pierwsze powitania`, title_native: `Salam pertama`, focus: `Zaczniesz od najprostszych powitań i pożegnań, przydatnych zaraz po przylocie do Dżakarty lub Denpasar. Nauczysz się mówić uprzejmie, ale naturalnie.`, vocab: [{id: `halo`, pl: `cześć`, ipa: `ha-lo`},{id: `selamat pagi`, pl: `dzień dobry rano`, ipa: `sə-la-mat pa-gi`},{id: `selamat siang`, pl: `dzień dobry w południe`, ipa: `sə-la-mat sjang`},{id: `selamat sore`, pl: `dzień dobry po południu`, ipa: `sə-la-mat so-re`},{id: `selamat malam`, pl: `dobry wieczór / dobranoc`, ipa: `sə-la-mat ma-lam`},{id: `nama`, pl: `imię`, ipa: `na-ma`},{id: `saya`, pl: `ja`, ipa: `sa-ja`},{id: `Anda`, pl: `pan / pani / ty formalnie`, ipa: `an-da`},{id: `terima kasih`, pl: `dziękuję`, ipa: `tə-ri-ma ka-sih`},{id: `sampai jumpa`, pl: `do zobaczenia`, ipa: `sam-paj dżum-pa`}], phrases: [{id: `Halo, nama saya Anna.`, pl: `Cześć, mam na imię Anna.`, ipa: `ha-lo, na-ma sa-ja an-na`},{id: `Selamat pagi.`, pl: `Dzień dobry rano.`, ipa: `sə-la-mat pa-gi`},{id: `Apa kabar?`, pl: `Jak się masz?`, ipa: `a-pa ka-bar`},{id: `Kabar baik.`, pl: `Mam się dobrze.`, ipa: `ka-bar ba-ik`},{id: `Terima kasih.`, pl: `Dziękuję.`, ipa: `tə-ri-ma ka-sih`},{id: `Sampai jumpa.`, pl: `Do zobaczenia.`, ipa: `sam-paj dżum-pa`}], grammar: `W indonezyjskim czasownik nie zmienia się przez osoby, więc „saya” zawsze oznacza „ja”, a forma czasownika zostaje taka sama. „Selamat” pojawia się w wielu uprzejmych zwrotach i dosłownie niesie sens życzenia dobra lub bezpieczeństwa. W podróży lepiej zaczynać rozmowę od „selamat pagi/siang/sore/malam” niż od samego „halo” w bardziej formalnych sytuacjach.`, practice: [`Przedstaw się jednym zdaniem po indonezyjsku.`,`Powiedz „dzień dobry rano” i „dziękuję”.`,`Odpowiedz na pytanie „Apa kabar?”.`,`Dopasuj porę dnia do zwrotu: pagi, siang, sore, malam.`,`Wyobraź sobie, że wchodzisz do hotelu w Dżakarcie i przywitaj recepcjonistę.`]},{day: 2, title: `Uprzejme zwroty i podstawowe reakcje`, title_native: `Ungkapan sopan dan jawaban dasar`, focus: `Nauczysz się przepraszać, prosić i reagować w prostych sytuacjach na ulicy, w sklepie i w kawiarni w Yogyakarcie.`, vocab: [{id: `maaf`, pl: `przepraszam`, ipa: `ma-af`},{id: `tolong`, pl: `proszę o pomoc / proszę coś zrobić`, ipa: `to-long`},{id: `silakan`, pl: `proszę bardzo / zapraszam`, ipa: `si-la-kan`},{id: `ya`, pl: `tak`, ipa: `ja`},{id: `tidak`, pl: `nie`, ipa: `ti-dak`},{id: `bukan`, pl: `nie, to nie jest`, ipa: `bu-kan`},{id: `baik`, pl: `dobrze`, ipa: `ba-ik`},{id: `oke`, pl: `okej`, ipa: `o-ke`},{id: `permisi`, pl: `przepraszam, gdy przechodzisz`, ipa: `pər-mi-si`},{id: `sama-sama`, pl: `nie ma za co`, ipa: `sa-ma sa-ma`}], phrases: [{id: `Maaf.`, pl: `Przepraszam.`, ipa: `ma-af`},{id: `Permisi, boleh lewat?`, pl: `Przepraszam, czy mogę przejść?`, ipa: `pər-mi-si, bo-leh le-wat`},{id: `Tolong bantu saya.`, pl: `Proszę mi pomóc.`, ipa: `to-long ban-tu sa-ja`},{id: `Ya, benar.`, pl: `Tak, zgadza się.`, ipa: `ja, bə-nar`},{id: `Tidak, terima kasih.`, pl: `Nie, dziękuję.`, ipa: `ti-dak, tə-ri-ma ka-sih`},{id: `Sama-sama.`, pl: `Nie ma za co.`, ipa: `sa-ma sa-ma`}], grammar: `W indonezyjskim „tidak” używa się do zaprzeczania czasownikom i przymiotnikom, a „bukan” do zaprzeczania rzeczownikom lub tożsamości. Na początku nie musisz znać wszystkich różnic idealnie, ale zapamiętaj: „tidak mau” to „nie chcę”, a „bukan hotel” to „to nie hotel”. „Tolong” przed czasownikiem brzmi uprzejmie i praktycznie.`, practice: [`Powiedz „nie, dziękuję” po indonezyjsku.`,`Poproś kogoś, żeby ci pomógł.`,`Powiedz „przepraszam, czy mogę przejść?”.`,`Wybierz „tidak” albo „bukan”: ___ restoran.`,`Odegraj krótką scenkę, w której odmawiasz sprzedawcy na targu.`]},{day: 3, title: `Liczby od zera do dwudziestu`, title_native: `Angka nol sampai dua puluh`, focus: `Liczby są niezbędne przy płaceniu, zamawianiu jedzenia i pytaniu o numer autobusu w Dżakarcie. Dziś nauczysz się najważniejszego zestawu startowego.`, vocab: [{id: `nol`, pl: `zero`, ipa: `nol`},{id: `satu`, pl: `jeden`, ipa: `sa-tu`},{id: `dua`, pl: `dwa`, ipa: `du-a`},{id: `tiga`, pl: `trzy`, ipa: `ti-ga`},{id: `empat`, pl: `cztery`, ipa: `əm-pat`},{id: `lima`, pl: `pięć`, ipa: `li-ma`},{id: `enam`, pl: `sześć`, ipa: `ə-nam`},{id: `tujuh`, pl: `siedem`, ipa: `tu-dżuh`},{id: `delapan`, pl: `osiem`, ipa: `də-la-pan`},{id: `sepuluh`, pl: `dziesięć`, ipa: `sə-pu-luh`}], phrases: [{id: `Satu kopi, tolong.`, pl: `Jedną kawę, proszę.`, ipa: `sa-tu ko-pi, to-long`},{id: `Dua tiket, tolong.`, pl: `Dwa bilety, proszę.`, ipa: `du-a ti-ket, to-long`},{id: `Berapa harganya?`, pl: `Ile to kosztuje?`, ipa: `bə-ra-pa har-ga-nja`},{id: `Harganya lima ribu.`, pl: `Cena to pięć tysięcy.`, ipa: `har-ga-nja li-ma ri-bu`},{id: `Saya mau tiga.`, pl: `Chcę trzy.`, ipa: `sa-ja ma-u ti-ga`},{id: `Nomor sepuluh.`, pl: `Numer dziesięć.`, ipa: `no-mor sə-pu-luh`}], grammar: `Rzeczowniki w indonezyjskim zwykle nie mają liczby mnogiej tak jak po polsku. „Satu tiket” to „jeden bilet”, a „dua tiket” to „dwa bilety” — słowo „tiket” się nie zmienia. To bardzo ułatwia szybkie mówienie podczas zakupów.`, practice: [`Policz po indonezyjsku od 1 do 10.`,`Zamów dwie kawy.`,`Zapytaj o cenę.`,`Powiedz „numer dziesięć”.`,`Przećwicz: satu tiket, dua tiket, tiga tiket.`]},{day: 4, title: `Więcej liczb i ceny`, title_native: `Angka lebih banyak dan harga`, focus: `W Indonezji często usłyszysz ceny w tysiącach rupii. Nauczysz się mówić o kwotach na targu, w taksówce i przy kasie.`, vocab: [{id: `sebelas`, pl: `jedenaście`, ipa: `sə-bə-las`},{id: `dua belas`, pl: `dwanaście`, ipa: `du-a bə-las`},{id: `lima belas`, pl: `piętnaście`, ipa: `li-ma bə-las`},{id: `dua puluh`, pl: `dwadzieścia`, ipa: `du-a pu-luh`},{id: `tiga puluh`, pl: `trzydzieści`, ipa: `ti-ga pu-luh`},{id: `seratus`, pl: `sto`, ipa: `sə-ra-tus`},{id: `seribu`, pl: `tysiąc`, ipa: `sə-ri-bu`},{id: `ribu`, pl: `tysiąc`, ipa: `ri-bu`},{id: `harga`, pl: `cena`, ipa: `har-ga`},{id: `uang`, pl: `pieniądze`, ipa: `u-ang`}], phrases: [{id: `Berapa harga ini?`, pl: `Ile kosztuje to?`, ipa: `bə-ra-pa har-ga i-ni`},{id: `Ini sepuluh ribu.`, pl: `To dziesięć tysięcy.`, ipa: `i-ni sə-pu-luh ri-bu`},{id: `Terlalu mahal.`, pl: `Za drogo.`, ipa: `tər-la-lu ma-hal`},{id: `Ada yang lebih murah?`, pl: `Czy jest coś tańszego?`, ipa: `a-da jang lə-bih mu-rah`},{id: `Saya bayar tunai.`, pl: `Płacę gotówką.`, ipa: `sa-ja ba-jar tu-naj`},{id: `Saya bayar dengan kartu.`, pl: `Płacę kartą.`, ipa: `sa-ja ba-jar də-ngan kar-tu`}], grammar: `„Ini” oznacza „to” dla rzeczy blisko ciebie, a „itu” oznacza „tamto” lub „to” dalej od ciebie. Pytanie „Berapa harga ini?” jest bardzo praktyczne, bo nie musisz znać nazwy przedmiotu. Wymowa „ribu” jest ważna, bo większość codziennych cen usłyszysz właśnie w tysiącach.`, practice: [`Zapytaj o cenę przedmiotu w sklepie.`,`Powiedz, że coś jest za drogie.`,`Powiedz „płacę kartą”.`,`Przeczytaj na głos: sepuluh ribu, dua puluh ribu, seratus ribu.`,`Wyobraź sobie zakup wody za 10 000 rupii i powiedz całe zdanie.`]},{day: 5, title: `Pytania: kto, co, gdzie`, title_native: `Pertanyaan: siapa, apa, di mana`, focus: `Nauczysz się zadawać podstawowe pytania podczas zwiedzania Bandung lub Bali. To pozwoli ci pytać o miejsca, osoby i rzeczy bez budowania długich zdań.`, vocab: [{id: `apa`, pl: `co`, ipa: `a-pa`},{id: `siapa`, pl: `kto`, ipa: `sja-pa`},{id: `di mana`, pl: `gdzie`, ipa: `di ma-na`},{id: `kapan`, pl: `kiedy`, ipa: `ka-pan`},{id: `kenapa`, pl: `dlaczego`, ipa: `kə-na-pa`},{id: `bagaimana`, pl: `jak`, ipa: `ba-gaj-ma-na`},{id: `ini`, pl: `to`, ipa: `i-ni`},{id: `itu`, pl: `tamto`, ipa: `i-tu`},{id: `orang`, pl: `osoba / człowiek`, ipa: `o-rang`},{id: `tempat`, pl: `miejsce`, ipa: `təm-pat`}], phrases: [{id: `Apa ini?`, pl: `Co to jest?`, ipa: `a-pa i-ni`},{id: `Siapa nama Anda?`, pl: `Jak się pan/pani nazywa?`, ipa: `sja-pa na-ma an-da`},{id: `Di mana hotel saya?`, pl: `Gdzie jest mój hotel?`, ipa: `di ma-na ho-tel sa-ja`},{id: `Kapan buka?`, pl: `Kiedy jest otwarte?`, ipa: `ka-pan bu-ka`},{id: `Bagaimana caranya?`, pl: `Jak to zrobić?`, ipa: `ba-gaj-ma-na tʃa-ra-nja`},{id: `Kenapa tutup?`, pl: `Dlaczego jest zamknięte?`, ipa: `kə-na-pa tu-tup`}], grammar: `W indonezyjskim pytania często tworzy się przez dodanie słowa pytającego, bez zmiany szyku całego zdania. „Hotel di mana?” w mowie potocznej też może znaczyć „Gdzie jest hotel?”. Formalniej i jaśniej powiesz „Di mana hotel saya?”.`, practice: [`Zapytaj „co to jest?”.`,`Zapytaj o czyjeś imię.`,`Zapytaj, gdzie jest twój hotel.`,`Ułóż pytanie ze słowem „kapan”.`,`Przećwicz różnicę między „ini” i „itu”, wskazując przedmioty wokół siebie.`]},{day: 6, title: `Na lotnisku`, title_native: `Di bandara`, focus: `Ten dzień przygotuje cię do przylotu na lotnisko Soekarno-Hatta w Dżakarcie lub Ngurah Rai na Bali. Nauczysz się słów związanych z bagażem, paszportem i wyjściem.`, vocab: [{id: `bandara`, pl: `lotnisko`, ipa: `ban-da-ra`},{id: `paspor`, pl: `paszport`, ipa: `pas-por`},{id: `visa`, pl: `wiza`, ipa: `wi-sa`},{id: `bagasi`, pl: `bagaż`, ipa: `ba-ga-si`},{id: `koper`, pl: `walizka`, ipa: `ko-pər`},{id: `pintu keluar`, pl: `wyjście`, ipa: `pin-tu kə-lu-ar`},{id: `kedatangan`, pl: `przyloty`, ipa: `kə-da-ta-ngan`},{id: `keberangkatan`, pl: `odloty`, ipa: `kə-bə-rang-ka-tan`},{id: `tiket`, pl: `bilet`, ipa: `ti-ket`},{id: `petugas`, pl: `pracownik / funkcjonariusz`, ipa: `pə-tu-gas`}], phrases: [{id: `Di mana bagasi saya?`, pl: `Gdzie jest mój bagaż?`, ipa: `di ma-na ba-ga-si sa-ja`},{id: `Ini paspor saya.`, pl: `To mój paszport.`, ipa: `i-ni pas-por sa-ja`},{id: `Saya turis.`, pl: `Jestem turystą/turystką.`, ipa: `sa-ja tu-ris`},{id: `Saya dari Polandia.`, pl: `Jestem z Polski.`, ipa: `sa-ja da-ri po-lan-di-a`},{id: `Di mana pintu keluar?`, pl: `Gdzie jest wyjście?`, ipa: `di ma-na pin-tu kə-lu-ar`},{id: `Saya punya tiket.`, pl: `Mam bilet.`, ipa: `sa-ja pu-nja ti-ket`}], grammar: `„Saya punya...” oznacza „mam...” i jest bardzo łatwą konstrukcją podróżną. Możesz powiedzieć „Saya punya paspor”, „Saya punya tiket” albo „Saya punya koper”. „Dari” oznacza „z” w sensie pochodzenia lub kierunku wyjścia.`, practice: [`Powiedz, że jesteś z Polski.`,`Powiedz, że masz bilet.`,`Zapytaj, gdzie jest wyjście.`,`Zapytaj o swój bagaż.`,`Odegraj krótką rozmowę z pracownikiem kontroli paszportowej.`]},{day: 7, title: `Hotel i zameldowanie`, title_native: `Hotel dan check-in`, focus: `Nauczysz się zameldować w hotelu w Ubudzie, Dżakarcie lub Surabai. Skupimy się na rezerwacji, pokoju, kluczu i godzinach.`, vocab: [{id: `hotel`, pl: `hotel`, ipa: `ho-tel`},{id: `reservasi`, pl: `rezerwacja`, ipa: `re-sər-wa-si`},{id: `kamar`, pl: `pokój`, ipa: `ka-mar`},{id: `kunci`, pl: `klucz`, ipa: `kun-tʃi`},{id: `lantai`, pl: `piętro`, ipa: `lan-taj`},{id: `sarapan`, pl: `śniadanie`, ipa: `sa-ra-pan`},{id: `malam`, pl: `noc / wieczór`, ipa: `ma-lam`},{id: `check-in`, pl: `zameldowanie`, ipa: `czek-in`},{id: `check-out`, pl: `wymeldowanie`, ipa: `czek-aut`},{id: `resepsionis`, pl: `recepcjonista`, ipa: `re-sep-sjo-nis`}], phrases: [{id: `Saya punya reservasi.`, pl: `Mam rezerwację.`, ipa: `sa-ja pu-nja re-sər-wa-si`},{id: `Atas nama Anna.`, pl: `Na nazwisko Anna.`, ipa: `a-tas na-ma an-na`},{id: `Di mana kamar saya?`, pl: `Gdzie jest mój pokój?`, ipa: `di ma-na ka-mar sa-ja`},{id: `Kamar di lantai berapa?`, pl: `Na którym piętrze jest pokój?`, ipa: `ka-mar di lan-taj bə-ra-pa`},{id: `Apakah sarapan termasuk?`, pl: `Czy śniadanie jest wliczone?`, ipa: `a-pa-kah sa-ra-pan tər-ma-suk`},{id: `Jam berapa check-out?`, pl: `O której jest wymeldowanie?`, ipa: `dżam bə-ra-pa czek-aut`}], grammar: `„Apakah” to formalny znacznik pytania tak/nie. Możesz powiedzieć „Apakah sarapan termasuk?” zamiast polegać tylko na intonacji. W hotelach i urzędowych sytuacjach „apakah” brzmi jasno i uprzejmie.`, practice: [`Powiedz, że masz rezerwację.`,`Podaj nazwisko przy zameldowaniu.`,`Zapytaj, czy śniadanie jest wliczone.`,`Zapytaj o godzinę wymeldowania.`,`Przećwicz zdanie „Kamar di lantai berapa?”.`]},{day: 8, title: `Kierunki i orientacja`, title_native: `Arah dan lokasi`, focus: `Dziś nauczysz się pytać o drogę w centrum Dżakarty, przy plaży w Sanur lub w okolicach świątyń na Bali. Poznasz słowa „lewo”, „prawo” i „prosto”.`, vocab: [{id: `kiri`, pl: `lewo`, ipa: `ki-ri`},{id: `kanan`, pl: `prawo`, ipa: `ka-nan`},{id: `lurus`, pl: `prosto`, ipa: `lu-rus`},{id: `dekat`, pl: `blisko`, ipa: `də-kat`},{id: `jauh`, pl: `daleko`, ipa: `dża-uh`},{id: `jalan`, pl: `droga / ulica`, ipa: `dża-lan`},{id: `belok`, pl: `skręcić`, ipa: `be-lok`},{id: `depan`, pl: `przód / przed`, ipa: `də-pan`},{id: `belakang`, pl: `tył / za`, ipa: `bə-la-kang`},{id: `sini`, pl: `tutaj`, ipa: `si-ni`}], phrases: [{id: `Di mana jalan ini?`, pl: `Gdzie jest ta ulica?`, ipa: `di ma-na dża-lan i-ni`},{id: `Jalan lurus.`, pl: `Idź prosto.`, ipa: `dża-lan lu-rus`},{id: `Belok kiri.`, pl: `Skręć w lewo.`, ipa: `be-lok ki-ri`},{id: `Belok kanan.`, pl: `Skręć w prawo.`, ipa: `be-lok ka-nan`},{id: `Apakah dekat?`, pl: `Czy to blisko?`, ipa: `a-pa-kah də-kat`},{id: `Saya tersesat.`, pl: `Zgubiłem/Zgubiłam się.`, ipa: `sa-ja tər-sə-sat`}], grammar: `„Jalan” może oznaczać zarówno „ulicę”, jak i „iść / jechać”, zależnie od kontekstu. „Jalan lurus” dosłownie znaczy coś jak „idź prosto”. W praktyce wystarczy połączyć „belok” z „kiri” lub „kanan”, aby zrozumiale poprosić o kierunek.`, practice: [`Powiedz „idź prosto”.`,`Powiedz „skręć w prawo”.`,`Zapytaj, czy miejsce jest blisko.`,`Powiedz, że się zgubiłeś lub zgubiłaś.`,`Narysuj prostą mapę i opisz drogę trzema indonezyjskimi zwrotami.`]},{day: 9, title: `Transport miejski`, title_native: `Transportasi kota`, focus: `Nauczysz się korzystać z autobusu, pociągu i aplikacji transportowej w Dżakarcie lub Surabai. Ten dzień pomoże ci pytać o trasę i przystanek.`, vocab: [{id: `bus`, pl: `autobus`, ipa: `bus`},{id: `kereta`, pl: `pociąg`, ipa: `kə-re-ta`},{id: `stasiun`, pl: `stacja`, ipa: `sta-sjun`},{id: `halte`, pl: `przystanek`, ipa: `hal-te`},{id: `taksi`, pl: `taksówka`, ipa: `tak-si`},{id: `ojek`, pl: `motocyklowa taksówka`, ipa: `o-dżek`},{id: `tujuan`, pl: `cel podróży`, ipa: `tu-dżu-an`},{id: `rute`, pl: `trasa`, ipa: `ru-te`},{id: `macet`, pl: `korek uliczny`, ipa: `ma-czet`},{id: `turun`, pl: `wysiadać / zejść`, ipa: `tu-run`}], phrases: [{id: `Saya mau ke stasiun.`, pl: `Chcę jechać na stację.`, ipa: `sa-ja ma-u kə sta-sjun`},{id: `Bus ini ke mana?`, pl: `Dokąd jedzie ten autobus?`, ipa: `bus i-ni kə ma-na`},{id: `Saya turun di sini.`, pl: `Wysiadam tutaj.`, ipa: `sa-ja tu-run di si-ni`},{id: `Apakah jauh?`, pl: `Czy to daleko?`, ipa: `a-pa-kah dża-uh`},{id: `Berapa lama?`, pl: `Jak długo?`, ipa: `bə-ra-pa la-ma`},{id: `Jalan macet.`, pl: `Droga jest zakorkowana.`, ipa: `dża-lan ma-czet`}], grammar: `„Ke” oznacza „do” jako kierunek ruchu: „ke hotel”, „ke bandara”, „ke stasiun”. „Di” oznacza „w” lub „na” jako lokalizację: „di hotel”, „di bandara”, „di sini”. To jedna z najważniejszych różnic dla podróżnika.`, practice: [`Powiedz, że chcesz jechać na stację.`,`Zapytaj, dokąd jedzie autobus.`,`Powiedz kierowcy, że wysiadasz tutaj.`,`Użyj „ke” w trzech zdaniach.`,`Użyj „di” w trzech zdaniach.`]},{day: 10, title: `Taksówka i aplikacje przejazdowe`, title_native: `Taksi dan aplikasi perjalanan`, focus: `W Indonezji popularne są taksówki i przejazdy przez aplikacje. Nauczysz się podawać adres, pytać o cenę i mówić kierowcy, gdzie się zatrzymać.`, vocab: [{id: `alamat`, pl: `adres`, ipa: `a-la-mat`},{id: `pengemudi`, pl: `kierowca`, ipa: `pə-ngə-mu-di`},{id: `mobil`, pl: `samochód`, ipa: `mo-bil`},{id: `motor`, pl: `motocykl`, ipa: `mo-tor`},{id: `berhenti`, pl: `zatrzymać się`, ipa: `bər-hən-ti`},{id: `cepat`, pl: `szybko`, ipa: `czə-pat`},{id: `pelan-pelan`, pl: `powoli`, ipa: `pə-lan pə-lan`},{id: `lurus saja`, pl: `tylko prosto`, ipa: `lu-rus sa-dża`},{id: `sampai`, pl: `dotrzeć / aż do`, ipa: `sam-paj`},{id: `di depan`, pl: `z przodu / przed`, ipa: `di də-pan`}], phrases: [{id: `Ini alamatnya.`, pl: `Oto adres.`, ipa: `i-ni a-la-mat-nja`},{id: `Tolong ke hotel ini.`, pl: `Proszę do tego hotelu.`, ipa: `to-long kə ho-tel i-ni`},{id: `Berhenti di sini, tolong.`, pl: `Proszę zatrzymać się tutaj.`, ipa: `bər-hən-ti di si-ni, to-long`},{id: `Pelan-pelan, ya.`, pl: `Proszę powoli.`, ipa: `pə-lan pə-lan, ja`},{id: `Lurus saja.`, pl: `Proszę tylko prosto.`, ipa: `lu-rus sa-dża`},{id: `Kita sudah sampai?`, pl: `Czy już dotarliśmy?`, ipa: `ki-ta su-dah sam-paj`}], grammar: `„Tolong” może stać na początku lub na końcu zdania i dodaje uprzejmości. „Saja” oznacza „tylko” lub „po prostu”, więc „lurus saja” to „prosto, po prostu”. „Kita” oznacza „my” razem z rozmówcą, przydatne w zdaniu „Kita sudah sampai?”.`, practice: [`Powiedz kierowcy „oto adres”.`,`Poproś o zatrzymanie się tutaj.`,`Powiedz „proszę powoli”.`,`Zapytaj, czy już dotarliście.`,`Wyobraź sobie przejazd z lotniska do hotelu i ułóż trzy krótkie zdania.`]},{day: 11, title: `Kawiarnia i proste zamówienia`, title_native: `Kafe dan pesanan sederhana`, focus: `Nauczysz się zamawiać kawę, herbatę i drobne przekąski w kawiarni w Seminyak, Ubudzie lub Dżakarcie.`, vocab: [{id: `kopi`, pl: `kawa`, ipa: `ko-pi`},{id: `teh`, pl: `herbata`, ipa: `teh`},{id: `air`, pl: `woda`, ipa: `a-ir`},{id: `gula`, pl: `cukier`, ipa: `gu-la`},{id: `susu`, pl: `mleko`, ipa: `su-su`},{id: `es`, pl: `lód`, ipa: `es`},{id: `panas`, pl: `gorący`, ipa: `pa-nas`},{id: `dingin`, pl: `zimny`, ipa: `ding-in`},{id: `roti`, pl: `chleb / bułka`, ipa: `ro-ti`},{id: `kue`, pl: `ciasto / ciastko`, ipa: `ku-e`}], phrases: [{id: `Saya mau kopi.`, pl: `Chcę kawę.`, ipa: `sa-ja ma-u ko-pi`},{id: `Kopi panas, tolong.`, pl: `Gorącą kawę, proszę.`, ipa: `ko-pi pa-nas, to-long`},{id: `Tanpa gula.`, pl: `Bez cukru.`, ipa: `tan-pa gu-la`},{id: `Dengan susu.`, pl: `Z mlekiem.`, ipa: `də-ngan su-su`},{id: `Air dingin, tolong.`, pl: `Zimną wodę, proszę.`, ipa: `a-ir ding-in, to-long`},{id: `Untuk di sini.`, pl: `Na miejscu.`, ipa: `un-tuk di si-ni`}], grammar: `„Dengan” oznacza „z”, a „tanpa” oznacza „bez”. Możesz ich używać bardzo szeroko: „dengan susu”, „tanpa gula”, „tanpa es”. W zamówieniach nie trzeba budować pełnego zdania — krótkie frazy są naturalne.`, practice: [`Zamów gorącą kawę.`,`Powiedz „bez cukru”.`,`Zamów zimną wodę.`,`Powiedz, że chcesz coś na miejscu.`,`Stwórz własne zamówienie z „dengan” i „tanpa”.`]},{day: 12, title: `Restauracja i jedzenie`, title_native: `Restoran dan makanan`, focus: `Dziś nauczysz się zamawiać jedzenie w lokalnym warungu lub restauracji w Indonezji. Poznasz nazwy podstawowych potraw i przydatne zwroty przy stole.`, vocab: [{id: `makanan`, pl: `jedzenie`, ipa: `ma-ka-nan`},{id: `nasi`, pl: `ryż`, ipa: `na-si`},{id: `mie`, pl: `makaron`, ipa: `mi`},{id: `ayam`, pl: `kurczak`, ipa: `a-jam`},{id: `ikan`, pl: `ryba`, ipa: `i-kan`},{id: `sayur`, pl: `warzywa`, ipa: `sa-jur`},{id: `pedas`, pl: `ostre`, ipa: `pə-das`},{id: `enak`, pl: `smaczne`, ipa: `e-nak`},{id: `menu`, pl: `menu`, ipa: `me-nu`},{id: `piring`, pl: `talerz`, ipa: `pi-ring`}], phrases: [{id: `Boleh lihat menu?`, pl: `Czy mogę zobaczyć menu?`, ipa: `bo-leh li-hat me-nu`},{id: `Saya mau nasi goreng.`, pl: `Chcę smażony ryż.`, ipa: `sa-ja ma-u na-si go-reng`},{id: `Tidak pedas, tolong.`, pl: `Nieostre, proszę.`, ipa: `ti-dak pə-das, to-long`},{id: `Ini enak sekali.`, pl: `To jest bardzo smaczne.`, ipa: `i-ni e-nak sə-ka-li`},{id: `Saya vegetarian.`, pl: `Jestem wegetarianinem/wegetarianką.`, ipa: `sa-ja we-ge-ta-rjan`},{id: `Minta bill, tolong.`, pl: `Poproszę rachunek.`, ipa: `min-ta bil, to-long`}], grammar: `„Boleh” oznacza „można” lub „czy mogę”, dlatego jest bardzo przydatne przy proszeniu o menu, zdjęcie lub wejście gdzieś. „Minta” oznacza „poproszę” w sensie „proszę dać”. W restauracji „Minta bill” jest powszechnie rozumiane, choć bardziej indonezyjskie byłoby „Minta tagihan”.`, practice: [`Poproś o menu.`,`Zamów nasi goreng.`,`Powiedz, że nie chcesz ostrego jedzenia.`,`Powiedz, że danie jest bardzo smaczne.`,`Poproś o rachunek.`]},{day: 13, title: `Dieta, alergie i preferencje`, title_native: `Diet, alergi, dan pilihan makanan`, focus: `Ten dzień pomoże ci jasno powiedzieć, czego nie jesz lub na co masz alergię. To szczególnie ważne w miejscach, gdzie potrawy mogą zawierać orzeszki, owoce morza albo dużo chili.`, vocab: [{id: `alergi`, pl: `alergia`, ipa: `a-ler-gi`},{id: `kacang`, pl: `orzechy / fasola`, ipa: `ka-czang`},{id: `udang`, pl: `krewetka`, ipa: `u-dang`},{id: `daging`, pl: `mięso`, ipa: `da-ging`},{id: `babi`, pl: `wieprzowina`, ipa: `ba-bi`},{id: `sapi`, pl: `wołowina`, ipa: `sa-pi`},{id: `telur`, pl: `jajko`, ipa: `tə-lur`},{id: `saus`, pl: `sos`, ipa: `saus`},{id: `minyak`, pl: `olej`, ipa: `mi-njak`},{id: `aman`, pl: `bezpieczny`, ipa: `a-man`}], phrases: [{id: `Saya alergi kacang.`, pl: `Mam alergię na orzechy.`, ipa: `sa-ja a-ler-gi ka-czang`},{id: `Apakah ada udang?`, pl: `Czy są tam krewetki?`, ipa: `a-pa-kah a-da u-dang`},{id: `Saya tidak makan daging.`, pl: `Nie jem mięsa.`, ipa: `sa-ja ti-dak ma-kan da-ging`},{id: `Tanpa babi, tolong.`, pl: `Bez wieprzowiny, proszę.`, ipa: `tan-pa ba-bi, to-long`},{id: `Apakah ini aman?`, pl: `Czy to jest bezpieczne?`, ipa: `a-pa-kah i-ni a-man`},{id: `Saya tidak bisa makan pedas.`, pl: `Nie mogę jeść ostrego.`, ipa: `sa-ja ti-dak bi-sa ma-kan pə-das`}], grammar: `„Bisa” oznacza „móc / potrafić”. „Saya tidak bisa makan pedas” dosłownie znaczy „nie mogę jeść ostrego” i brzmi naturalnie. Przy alergiach warto mówić prosto i powtarzać najważniejsze słowo, np. „alergi kacang”.`, practice: [`Powiedz, że masz alergię na orzechy.`,`Zapytaj, czy potrawa zawiera krewetki.`,`Powiedz, że nie jesz mięsa.`,`Powiedz „bez wieprzowiny”.`,`Ułóż własne zdanie z „Saya tidak bisa...”.`]},{day: 14, title: `Zakupy na targu`, title_native: `Belanja di pasar`, focus: `Nauczysz się kupować owoce, pamiątki i drobne rzeczy na targu w Ubudzie lub Yogyakarcie. Skupimy się na cenie, negocjacji i ilości.`, vocab: [{id: `pasar`, pl: `targ`, ipa: `pa-sar`},{id: `toko`, pl: `sklep`, ipa: `to-ko`},{id: `buah`, pl: `owoc`, ipa: `bu-ah`},{id: `pisang`, pl: `banan`, ipa: `pi-sang`},{id: `mangga`, pl: `mango`, ipa: `mang-ga`},{id: `oleh-oleh`, pl: `pamiątka / prezent z podróży`, ipa: `o-leh o-leh`},{id: `tas`, pl: `torba`, ipa: `tas`},{id: `baju`, pl: `koszula / ubranie`, ipa: `ba-dżu`},{id: `murah`, pl: `tani`, ipa: `mu-rah`},{id: `mahal`, pl: `drogi`, ipa: `ma-hal`}], phrases: [{id: `Saya hanya lihat-lihat.`, pl: `Tylko się rozglądam.`, ipa: `sa-ja ha-nja li-hat li-hat`},{id: `Berapa harga tas ini?`, pl: `Ile kosztuje ta torba?`, ipa: `bə-ra-pa har-ga tas i-ni`},{id: `Bisa lebih murah?`, pl: `Czy może być taniej?`, ipa: `bi-sa lə-bih mu-rah`},{id: `Saya beli ini.`, pl: `Kupuję to.`, ipa: `sa-ja bə-li i-ni`},{id: `Saya mau dua mangga.`, pl: `Chcę dwa mango.`, ipa: `sa-ja ma-u du-a mang-ga`},{id: `Ada ukuran lain?`, pl: `Czy jest inny rozmiar?`, ipa: `a-da u-ku-ran la-in`}], grammar: `Powtórzenie czasownika może tworzyć bardziej swobodny sens, np. „lihat-lihat” oznacza „rozglądać się”. To bardzo przydatna fraza na targu, gdy sprzedawca aktywnie zachęca do zakupu. „Bisa lebih murah?” jest prostym, grzecznym sposobem na negocjowanie ceny.`, practice: [`Powiedz, że tylko się rozglądasz.`,`Zapytaj o cenę torby.`,`Poproś o niższą cenę.`,`Powiedz, że kupujesz to.`,`Zamów dwa mango.`]},{day: 15, title: `Kolory, rozmiary i opisy`, title_native: `Warna, ukuran, dan deskripsi`, focus: `Dziś nauczysz się opisywać rzeczy podczas zakupów. Przyda się to, gdy szukasz koszulki, sarongu, kapelusza albo pamiątki.`, vocab: [{id: `warna`, pl: `kolor`, ipa: `war-na`},{id: `merah`, pl: `czerwony`, ipa: `me-rah`},{id: `biru`, pl: `niebieski`, ipa: `bi-ru`},{id: `putih`, pl: `biały`, ipa: `pu-tih`},{id: `hitam`, pl: `czarny`, ipa: `hi-tam`},{id: `besar`, pl: `duży`, ipa: `bə-sar`},{id: `kecil`, pl: `mały`, ipa: `kə-czil`},{id: `panjang`, pl: `długi`, ipa: `pan-dżang`},{id: `pendek`, pl: `krótki`, ipa: `pən-dek`},{id: `ukuran`, pl: `rozmiar`, ipa: `u-ku-ran`}], phrases: [{id: `Saya mau warna biru.`, pl: `Chcę kolor niebieski.`, ipa: `sa-ja ma-u war-na bi-ru`},{id: `Ada ukuran besar?`, pl: `Czy jest duży rozmiar?`, ipa: `a-da u-ku-ran bə-sar`},{id: `Ini terlalu kecil.`, pl: `To jest za małe.`, ipa: `i-ni tər-la-lu kə-czil`},{id: `Saya suka yang putih.`, pl: `Podoba mi się ten biały.`, ipa: `sa-ja su-ka jang pu-tih`},{id: `Boleh coba?`, pl: `Czy mogę przymierzyć?`, ipa: `bo-leh czo-ba`},{id: `Yang ini bagus.`, pl: `Ten jest ładny.`, ipa: `jang i-ni ba-gus`}], grammar: `„Yang” pomaga wskazać konkretną rzecz: „yang putih” to „ten biały”, „yang kecil” to „ten mały”. Możesz używać tego bez znajomości rzeczownika, co jest bardzo wygodne w sklepie. „Terlalu” oznacza „zbyt”, np. „terlalu kecil” albo „terlalu mahal”.`, practice: [`Powiedz, że chcesz kolor niebieski.`,`Zapytaj o duży rozmiar.`,`Powiedz, że coś jest za małe.`,`Wskaż „ten biały” po indonezyjsku.`,`Poproś o możliwość przymierzenia.`]},{day: 16, title: `Dni tygodnia i godziny`, title_native: `Hari dan jam`, focus: `Nauczysz się pytać o godziny otwarcia, terminy i dni tygodnia. To przydatne przy planowaniu wizyty w muzeum, restauracji lub na wycieczce.`, vocab: [{id: `hari`, pl: `dzień`, ipa: `ha-ri`},{id: `Senin`, pl: `poniedziałek`, ipa: `sə-nin`},{id: `Selasa`, pl: `wtorek`, ipa: `sə-la-sa`},{id: `Rabu`, pl: `środa`, ipa: `ra-bu`},{id: `Kamis`, pl: `czwartek`, ipa: `ka-mis`},{id: `Jumat`, pl: `piątek`, ipa: `dżu-mat`},{id: `Sabtu`, pl: `sobota`, ipa: `sab-tu`},{id: `Minggu`, pl: `niedziela`, ipa: `ming-gu`},{id: `jam`, pl: `godzina`, ipa: `dżam`},{id: `buka`, pl: `otwarte / otwierać`, ipa: `bu-ka`}], phrases: [{id: `Jam berapa sekarang?`, pl: `Która jest teraz godzina?`, ipa: `dżam bə-ra-pa sə-ka-rang`},{id: `Buka jam berapa?`, pl: `O której jest otwarte?`, ipa: `bu-ka dżam bə-ra-pa`},{id: `Tutup hari Minggu.`, pl: `Zamknięte w niedzielę.`, ipa: `tu-tup ha-ri ming-gu`},{id: `Saya datang hari Senin.`, pl: `Przyjdę w poniedziałek.`, ipa: `sa-ja da-tang ha-ri sə-nin`},{id: `Besok bisa?`, pl: `Czy jutro można?`, ipa: `be-sok bi-sa`},{id: `Hari ini penuh.`, pl: `Dzisiaj jest pełno.`, ipa: `ha-ri i-ni pə-nuh`}], grammar: `„Hari ini” oznacza „dzisiaj”, „besok” oznacza „jutro”, a „kemarin” oznacza „wczoraj”. „Jam” może znaczyć zarówno „godzina”, jak i „zegarek”. W pytaniach o czas używaj „jam berapa”.`, practice: [`Zapytaj, która jest godzina.`,`Zapytaj, o której coś jest otwarte.`,`Powiedz, że przyjdziesz w poniedziałek.`,`Powiedz, że miejsce jest zamknięte w niedzielę.`,`Wymień dni tygodnia po indonezyjsku.`]},{day: 17, title: `Umawianie planów`, title_native: `Membuat rencana`, focus: `Ten dzień pomoże ci ustalać proste plany z przewodnikiem, znajomym lub gospodarzem noclegu. Nauczysz się mówić „dzisiaj”, „jutro”, „później” i „teraz”.`, vocab: [{id: `sekarang`, pl: `teraz`, ipa: `sə-ka-rang`},{id: `nanti`, pl: `później`, ipa: `nan-ti`},{id: `besok`, pl: `jutro`, ipa: `be-sok`},{id: `kemarin`, pl: `wczoraj`, ipa: `kə-ma-rin`},{id: `pagi`, pl: `rano`, ipa: `pa-gi`},{id: `siang`, pl: `południe / dzień`, ipa: `sjang`},{id: `sore`, pl: `popołudnie`, ipa: `so-re`},{id: `malam`, pl: `wieczór / noc`, ipa: `ma-lam`},{id: `rencana`, pl: `plan`, ipa: `rən-tʃa-na`},{id: `bertemu`, pl: `spotkać się`, ipa: `bər-tə-mu`}], phrases: [{id: `Kita bertemu besok.`, pl: `Spotkamy się jutro.`, ipa: `ki-ta bər-tə-mu be-sok`},{id: `Saya datang nanti.`, pl: `Przyjdę później.`, ipa: `sa-ja da-tang nan-ti`},{id: `Sekarang saya sibuk.`, pl: `Teraz jestem zajęty/zajęta.`, ipa: `sə-ka-rang sa-ja si-buk`},{id: `Besok pagi bisa?`, pl: `Czy jutro rano można?`, ipa: `be-sok pa-gi bi-sa`},{id: `Jam lima sore.`, pl: `O piątej po południu.`, ipa: `dżam li-ma so-re`},{id: `Apa rencananya?`, pl: `Jaki jest plan?`, ipa: `a-pa rən-tʃa-na-nja`}], grammar: `W indonezyjskim czas przeszły i przyszły często wynika z kontekstu lub słów takich jak „besok”, „kemarin”, „nanti”. Czasownik nie zmienia formy. „Saya datang besok” oznacza „przyjdę jutro”, a „Saya datang kemarin” — „przyszedłem/przyszłam wczoraj”.`, practice: [`Powiedz, że spotkacie się jutro.`,`Zapytaj, czy jutro rano można.`,`Powiedz, że teraz jesteś zajęty lub zajęta.`,`Podaj godzinę piątą po południu.`,`Zapytaj „jaki jest plan?”.`]},{day: 18, title: `Pogoda i plaża`, title_native: `Cuaca dan pantai`, focus: `Nauczysz się rozmawiać o pogodzie podczas pobytu na Bali, Lomboku lub w Manado. Przyda się to przy planowaniu plaży, spaceru i wycieczek.`, vocab: [{id: `cuaca`, pl: `pogoda`, ipa: `czu-a-cza`},{id: `panas`, pl: `gorąco`, ipa: `pa-nas`},{id: `hujan`, pl: `deszcz`, ipa: `hu-dżan`},{id: `cerah`, pl: `słonecznie / jasno`, ipa: `czə-rah`},{id: `angin`, pl: `wiatr`, ipa: `ang-in`},{id: `pantai`, pl: `plaża`, ipa: `pan-taj`},{id: `laut`, pl: `morze`, ipa: `la-ut`},{id: `ombak`, pl: `fala`, ipa: `om-bak`},{id: `basah`, pl: `mokry`, ipa: `ba-sah`},{id: `kering`, pl: `suchy`, ipa: `kə-ring`}], phrases: [{id: `Cuaca panas hari ini.`, pl: `Dzisiaj jest gorąco.`, ipa: `czu-a-cza pa-nas ha-ri i-ni`},{id: `Akan hujan?`, pl: `Czy będzie padać?`, ipa: `a-kan hu-dżan`},{id: `Pantai di mana?`, pl: `Gdzie jest plaża?`, ipa: `pan-taj di ma-na`},{id: `Ombaknya besar.`, pl: `Fale są duże.`, ipa: `om-bak-nja bə-sar`},{id: `Saya mau ke laut.`, pl: `Chcę iść do morza.`, ipa: `sa-ja ma-u kə la-ut`},{id: `Hari ini cerah.`, pl: `Dzisiaj jest słonecznie.`, ipa: `ha-ri i-ni czə-rah`}], grammar: `„Akan” może wskazywać przyszłość, podobnie jak „będzie”. Nie zawsze jest konieczne, ale w pytaniu „Akan hujan?” pomaga jasno zapytać o prognozę. Słowo „-nya” w „ombaknya” może znaczyć „te fale / fale tutaj”.`, practice: [`Powiedz, że dzisiaj jest gorąco.`,`Zapytaj, czy będzie padać.`,`Zapytaj, gdzie jest plaża.`,`Powiedz, że fale są duże.`,`Zaplanuj krótko dzień na plaży, używając trzech indonezyjskich słów.`]},{day: 19, title: `Zdrowie i apteka`, title_native: `Kesehatan dan apotek`, focus: `Dziś nauczysz się opisywać podstawowe problemy zdrowotne i kupować lekarstwa w aptece w Indonezji. To ważne w podróży, szczególnie przy upale i zmianie jedzenia.`, vocab: [{id: `apotek`, pl: `apteka`, ipa: `a-po-tek`},{id: `obat`, pl: `lekarstwo`, ipa: `o-bat`},{id: `sakit`, pl: `chory / boli`, ipa: `sa-kit`},{id: `kepala`, pl: `głowa`, ipa: `kə-pa-la`},{id: `perut`, pl: `brzuch`, ipa: `pə-rut`},{id: `demam`, pl: `gorączka`, ipa: `də-mam`},{id: `mual`, pl: `mdłości`, ipa: `mu-al`},{id: `dokter`, pl: `lekarz`, ipa: `dok-tər`},{id: `air mineral`, pl: `woda mineralna`, ipa: `a-ir mi-ne-ral`},{id: `istirahat`, pl: `odpoczynek`, ipa: `is-ti-ra-hat`}], phrases: [{id: `Saya sakit.`, pl: `Jestem chory/chora.`, ipa: `sa-ja sa-kit`},{id: `Kepala saya sakit.`, pl: `Boli mnie głowa.`, ipa: `kə-pa-la sa-ja sa-kit`},{id: `Perut saya sakit.`, pl: `Boli mnie brzuch.`, ipa: `pə-rut sa-ja sa-kit`},{id: `Saya perlu obat.`, pl: `Potrzebuję lekarstwa.`, ipa: `sa-ja pər-lu o-bat`},{id: `Di mana apotek?`, pl: `Gdzie jest apteka?`, ipa: `di ma-na a-po-tek`},{id: `Saya perlu dokter.`, pl: `Potrzebuję lekarza.`, ipa: `sa-ja pər-lu dok-tər`}], grammar: `W indonezyjskim często mówi się „część ciała + saya + sakit”, czyli dosłownie „moja głowa boli”. To bardzo prosty schemat: „kepala saya sakit”, „perut saya sakit”. „Perlu” oznacza „potrzebować” i nie wymaga odmiany.`, practice: [`Powiedz, że boli cię głowa.`,`Powiedz, że boli cię brzuch.`,`Zapytaj, gdzie jest apteka.`,`Powiedz, że potrzebujesz lekarstwa.`,`Ułóż zdanie z „Saya perlu...”.`]},{day: 20, title: `Nagłe sytuacje`, title_native: `Situasi darurat`, focus: `Nauczysz się prostych zdań awaryjnych: jak poprosić o pomoc, zgłosić problem i powiedzieć, że coś zginęło. To przydatne w każdej części Indonezji.`, vocab: [{id: `darurat`, pl: `nagły wypadek`, ipa: `da-ru-rat`},{id: `bantuan`, pl: `pomoc`, ipa: `ban-tu-an`},{id: `polisi`, pl: `policja`, ipa: `po-li-si`},{id: `hilang`, pl: `zgubiony / zaginiony`, ipa: `hi-lang`},{id: `dicuri`, pl: `skradziony`, ipa: `di-czu-ri`},{id: `dompet`, pl: `portfel`, ipa: `dom-pet`},{id: `telepon`, pl: `telefon`, ipa: `te-le-pon`},{id: `bahaya`, pl: `niebezpieczeństwo`, ipa: `ba-ha-ja`},{id: `aman`, pl: `bezpieczny`, ipa: `a-man`},{id: `cepat`, pl: `szybko`, ipa: `czə-pat`}], phrases: [{id: `Tolong!`, pl: `Pomocy!`, ipa: `to-long`},{id: `Ini darurat.`, pl: `To nagły wypadek.`, ipa: `i-ni da-ru-rat`},{id: `Saya perlu bantuan.`, pl: `Potrzebuję pomocy.`, ipa: `sa-ja pər-lu ban-tu-an`},{id: `Dompet saya hilang.`, pl: `Zgubił mi się portfel.`, ipa: `dom-pet sa-ja hi-lang`},{id: `Telepon saya dicuri.`, pl: `Mój telefon został skradziony.`, ipa: `te-le-pon sa-ja di-czu-ri`},{id: `Panggil polisi, tolong.`, pl: `Proszę wezwać policję.`, ipa: `pang-gil po-li-si, to-long`}], grammar: `Przedrostek „di-” często wskazuje stronę bierną, np. „dicuri” oznacza „zostało skradzione”. Nie musisz teraz znać całej gramatyki, ale zapamiętaj gotową frazę „Telepon saya dicuri”. W sytuacji awaryjnej mów krótko i wyraźnie.`, practice: [`Krzyknij „pomocy” po indonezyjsku.`,`Powiedz, że potrzebujesz pomocy.`,`Powiedz, że zgubił ci się portfel.`,`Powiedz, że telefon został skradziony.`,`Poproś kogoś o wezwanie policji.`]},{day: 21, title: `Rozmowy towarzyskie`, title_native: `Percakapan sosial`, focus: `Dziś nauczysz się prowadzić krótką, przyjazną rozmowę z lokalną osobą w kawiarni, hostelu lub podczas wycieczki. Skupisz się na imieniu, kraju i podstawowych zainteresowaniach.`, vocab: [{id: `teman`, pl: `przyjaciel / znajomy`, ipa: `tə-man`},{id: `keluarga`, pl: `rodzina`, ipa: `kə-lu-ar-ga`},{id: `kerja`, pl: `praca`, ipa: `kər-dża`},{id: `liburan`, pl: `wakacje`, ipa: `li-bu-ran`},{id: `suka`, pl: `lubić`, ipa: `su-ka`},{id: `tinggal`, pl: `mieszkać`, ipa: `ting-gal`},{id: `kota`, pl: `miasto`, ipa: `ko-ta`},{id: `negara`, pl: `kraj`, ipa: `nə-ga-ra`},{id: `bahasa`, pl: `język`, ipa: `ba-ha-sa`},{id: `senang`, pl: `miło / szczęśliwy`, ipa: `sə-nang`}], phrases: [{id: `Saya dari Polandia.`, pl: `Jestem z Polski.`, ipa: `sa-ja da-ri po-lan-di-a`},{id: `Saya tinggal di Warsawa.`, pl: `Mieszkam w Warszawie.`, ipa: `sa-ja ting-gal di war-sa-wa`},{id: `Saya sedang liburan.`, pl: `Jestem na wakacjach.`, ipa: `sa-ja sə-dang li-bu-ran`},{id: `Saya suka Indonesia.`, pl: `Lubię Indonezję.`, ipa: `sa-ja su-ka in-do-ne-sja`},{id: `Senang bertemu Anda.`, pl: `Miło pana/panią poznać.`, ipa: `sə-nang bər-tə-mu an-da`},{id: `Anda bisa bahasa Inggris?`, pl: `Czy mówi pan/pani po angielsku?`, ipa: `an-da bi-sa ba-ha-sa ing-gris`}], grammar: `„Sedang” oznacza, że coś dzieje się teraz, podobnie jak „właśnie” lub „jestem w trakcie”. „Saya sedang liburan” brzmi naturalnie jako „jestem na wakacjach”. „Bahasa” oznacza „język”, więc „bahasa Indonesia” to język indonezyjski.`, practice: [`Powiedz, że jesteś z Polski.`,`Powiedz, gdzie mieszkasz.`,`Powiedz, że jesteś na wakacjach.`,`Powiedz, że lubisz Indonezję.`,`Zapytaj, czy rozmówca mówi po angielsku.`]},{day: 22, title: `Rodzina i ludzie`, title_native: `Keluarga dan orang`, focus: `Nauczysz się mówić o rodzinie i osobach, które podróżują z tobą. Przyda się to w hotelu, podczas wycieczki i w luźnej rozmowie.`, vocab: [{id: `ibu`, pl: `matka / pani`, ipa: `i-bu`},{id: `bapak`, pl: `ojciec / pan`, ipa: `ba-pak`},{id: `anak`, pl: `dziecko`, ipa: `a-nak`},{id: `suami`, pl: `mąż`, ipa: `su-a-mi`},{id: `istri`, pl: `żona`, ipa: `is-tri`},{id: `adik`, pl: `młodsze rodzeństwo`, ipa: `a-dik`},{id: `kakak`, pl: `starsze rodzeństwo`, ipa: `ka-kak`},{id: `orang tua`, pl: `rodzice`, ipa: `o-rang tu-a`},{id: `pasangan`, pl: `partner / partnerka`, ipa: `pa-sa-ngan`},{id: `sendiri`, pl: `sam / sama`, ipa: `sən-di-ri`}], phrases: [{id: `Saya datang sendiri.`, pl: `Przyjechałem/Przyjechałam sam/sama.`, ipa: `sa-ja da-tang sən-di-ri`},{id: `Saya datang dengan teman.`, pl: `Przyjechałem z przyjacielem.`, ipa: `sa-ja da-tang də-ngan tə-man`},{id: `Ini istri saya.`, pl: `To moja żona.`, ipa: `i-ni is-tri sa-ja`},{id: `Ini suami saya.`, pl: `To mój mąż.`, ipa: `i-ni su-a-mi sa-ja`},{id: `Kami punya dua anak.`, pl: `Mamy dwoje dzieci.`, ipa: `ka-mi pu-nja du-a a-nak`},{id: `Keluarga saya di Polandia.`, pl: `Moja rodzina jest w Polsce.`, ipa: `kə-lu-ar-ga sa-ja di po-lan-di-a`}], grammar: `„Kami” oznacza „my”, ale bez osoby, do której mówisz. „Kita” oznacza „my” razem z rozmówcą. Jeśli mówisz „kami punya dua anak”, nie włączasz rozmówcy do swojej rodziny, więc „kami” jest właściwe.`, practice: [`Powiedz, że podróżujesz sam lub sama.`,`Powiedz, że przyjechałeś z przyjacielem.`,`Przedstaw żonę lub męża w prostym zdaniu.`,`Powiedz, że twoja rodzina jest w Polsce.`,`Przećwicz różnicę między „kami” i „kita”.`]},{day: 23, title: `Zwiedzanie i bilety`, title_native: `Wisata dan tiket`, focus: `Dziś nauczysz się kupować bilety i pytać o atrakcje turystyczne, na przykład przy Borobudur, Prambanan lub muzeum w Dżakarcie.`, vocab: [{id: `wisata`, pl: `turystyka / wycieczka`, ipa: `wi-sa-ta`},{id: `tempat wisata`, pl: `atrakcja turystyczna`, ipa: `təm-pat wi-sa-ta`},{id: `candi`, pl: `świątynia`, ipa: `czan-di`},{id: `museum`, pl: `muzeum`, ipa: `mu-se-um`},{id: `tiket masuk`, pl: `bilet wstępu`, ipa: `ti-ket ma-suk`},{id: `pemandu`, pl: `przewodnik`, ipa: `pə-man-du`},{id: `foto`, pl: `zdjęcie`, ipa: `fo-to`},{id: `kamera`, pl: `aparat`, ipa: `ka-me-ra`},{id: `ramai`, pl: `tłoczno`, ipa: `ra-maj`},{id: `sepi`, pl: `spokojnie / pusto`, ipa: `sə-pi`}], phrases: [{id: `Berapa tiket masuk?`, pl: `Ile kosztuje bilet wstępu?`, ipa: `bə-ra-pa ti-ket ma-suk`},{id: `Saya mau satu tiket.`, pl: `Chcę jeden bilet.`, ipa: `sa-ja ma-u sa-tu ti-ket`},{id: `Boleh foto di sini?`, pl: `Czy można tu robić zdjęcia?`, ipa: `bo-leh fo-to di si-ni`},{id: `Ada pemandu?`, pl: `Czy jest przewodnik?`, ipa: `a-da pə-man-du`},{id: `Tempat ini ramai.`, pl: `To miejsce jest tłoczne.`, ipa: `təm-pat i-ni ra-maj`},{id: `Jam berapa tutup?`, pl: `O której zamykacie?`, ipa: `dżam bə-ra-pa tu-tup`}], grammar: `„Masuk” oznacza „wejść”, więc „tiket masuk” to dosłownie „bilet wejścia”. „Boleh foto di sini?” jest krótkie i naturalne, chociaż pełniej można powiedzieć „Boleh mengambil foto di sini?”. W podróży krótsza forma często wystarczy.`, practice: [`Zapytaj o cenę biletu wstępu.`,`Kup jeden bilet.`,`Zapytaj, czy można robić zdjęcia.`,`Zapytaj, czy jest przewodnik.`,`Powiedz, że miejsce jest tłoczne.`]},{day: 24, title: `Wycieczki i rezerwacje`, title_native: `Tur dan pemesanan`, focus: `Nauczysz się rezerwować wycieczkę, pytać o odbiór z hotelu i sprawdzać, co jest w cenie. To przydatne przy wyjazdach na wulkany, pola ryżowe lub wyspy.`, vocab: [{id: `tur`, pl: `wycieczka`, ipa: `tur`},{id: `pesan`, pl: `rezerwować / zamawiać`, ipa: `pə-san`},{id: `pemesanan`, pl: `rezerwacja`, ipa: `pə-mə-sa-nan`},{id: `jadwal`, pl: `harmonogram`, ipa: `dżad-wal`},{id: `jemput`, pl: `odebrać kogoś`, ipa: `dżəm-put`},{id: `termasuk`, pl: `wliczone`, ipa: `tər-ma-suk`},{id: `makan siang`, pl: `lunch / obiad`, ipa: `ma-kan sjang`},{id: `supir`, pl: `kierowca`, ipa: `su-pir`},{id: `perahu`, pl: `łódź`, ipa: `pə-ra-hu`},{id: `gunung`, pl: `góra`, ipa: `gu-nung`}], phrases: [{id: `Saya mau pesan tur.`, pl: `Chcę zarezerwować wycieczkę.`, ipa: `sa-ja ma-u pə-san tur`},{id: `Apakah jemput di hotel?`, pl: `Czy odbiór jest z hotelu?`, ipa: `a-pa-kah dżəm-put di ho-tel`},{id: `Makan siang termasuk?`, pl: `Czy lunch jest wliczony?`, ipa: `ma-kan sjang tər-ma-suk`},{id: `Jadwalnya bagaimana?`, pl: `Jaki jest harmonogram?`, ipa: `dżad-wal-nja ba-gaj-ma-na`},{id: `Tur mulai jam berapa?`, pl: `O której zaczyna się wycieczka?`, ipa: `tur mu-laj dżam bə-ra-pa`},{id: `Saya mau ke gunung.`, pl: `Chcę pojechać w góry.`, ipa: `sa-ja ma-u kə gu-nung`}], grammar: `Końcówka „-nya” często odnosi się do konkretnej rzeczy, o której już mówicie: „jadwalnya” to „harmonogram tej wycieczki”. W pytaniach o organizację możesz łączyć rzeczownik z „bagaimana”, czyli „jak?”. „Jadwalnya bagaimana?” brzmi naturalnie i praktycznie.`, practice: [`Powiedz, że chcesz zarezerwować wycieczkę.`,`Zapytaj, czy odbiór jest z hotelu.`,`Zapytaj, czy lunch jest wliczony.`,`Zapytaj, o której zaczyna się wycieczka.`,`Powiedz, że chcesz pojechać w góry.`]},{day: 25, title: `W hotelu: problemy i prośby`, title_native: `Di hotel: masalah dan permintaan`, focus: `Dziś nauczysz się zgłaszać problemy z pokojem, klimatyzacją, Wi-Fi i wodą. To bardzo praktyczne podczas pobytu w indonezyjskich hotelach i pensjonatach.`, vocab: [{id: `masalah`, pl: `problem`, ipa: `ma-sa-lah`},{id: `rusak`, pl: `zepsuty`, ipa: `ru-sak`},{id: `air panas`, pl: `ciepła woda`, ipa: `a-ir pa-nas`},{id: `AC`, pl: `klimatyzacja`, ipa: `a-ce`},{id: `Wi-Fi`, pl: `Wi-Fi`, ipa: `waj-faj`},{id: `handuk`, pl: `ręcznik`, ipa: `han-duk`},{id: `bersih`, pl: `czysty`, ipa: `bər-sih`},{id: `kotor`, pl: `brudny`, ipa: `ko-tor`},{id: `ganti`, pl: `wymienić`, ipa: `gan-ti`},{id: `segera`, pl: `natychmiast / szybko`, ipa: `sə-gə-ra`}], phrases: [{id: `Ada masalah di kamar.`, pl: `Jest problem w pokoju.`, ipa: `a-da ma-sa-lah di ka-mar`},{id: `AC tidak berfungsi.`, pl: `Klimatyzacja nie działa.`, ipa: `a-ce ti-dak bər-fung-si`},{id: `Wi-Fi tidak jalan.`, pl: `Wi-Fi nie działa.`, ipa: `waj-faj ti-dak dża-lan`},{id: `Tidak ada air panas.`, pl: `Nie ma ciepłej wody.`, ipa: `ti-dak a-da a-ir pa-nas`},{id: `Bisa ganti handuk?`, pl: `Czy można wymienić ręcznik?`, ipa: `bi-sa gan-ti han-duk`},{id: `Tolong cek segera.`, pl: `Proszę szybko sprawdzić.`, ipa: `to-long czek sə-gə-ra`}], grammar: `„Tidak ada” oznacza „nie ma”. To jedna z najważniejszych konstrukcji użytkowych: „tidak ada air”, „tidak ada Wi-Fi”, „tidak ada handuk”. „Berfungsi” oznacza „działać” w sensie technicznym, ale w mowie potocznej usłyszysz też „tidak jalan”.`, practice: [`Powiedz, że jest problem w pokoju.`,`Powiedz, że klimatyzacja nie działa.`,`Powiedz, że nie ma ciepłej wody.`,`Poproś o wymianę ręcznika.`,`Poproś, aby ktoś szybko to sprawdził.`]},{day: 26, title: `Poczta, SIM i internet`, title_native: `Pos, kartu SIM, dan internet`, focus: `Nauczysz się kupić kartę SIM, zapytać o internet i załatwić prostą sprawę w punkcie usługowym. To przydatne po przylocie i przy dłuższym pobycie.`, vocab: [{id: `kartu SIM`, pl: `karta SIM`, ipa: `kar-tu sim`},{id: `internet`, pl: `internet`, ipa: `in-tər-net`},{id: `paket data`, pl: `pakiet danych`, ipa: `pa-ket da-ta`},{id: `pulsa`, pl: `doładowanie`, ipa: `pul-sa`},{id: `nomor telepon`, pl: `numer telefonu`, ipa: `no-mor te-le-pon`},{id: `aktif`, pl: `aktywny`, ipa: `ak-tif`},{id: `pasang`, pl: `założyć / zamontować`, ipa: `pa-sang`},{id: `isi ulang`, pl: `doładować`, ipa: `i-si u-lang`},{id: `pos`, pl: `poczta`, ipa: `pos`},{id: `kirim`, pl: `wysłać`, ipa: `ki-rim`}], phrases: [{id: `Saya mau beli kartu SIM.`, pl: `Chcę kupić kartę SIM.`, ipa: `sa-ja ma-u bə-li kar-tu sim`},{id: `Ada paket data?`, pl: `Czy jest pakiet danych?`, ipa: `a-da pa-ket da-ta`},{id: `Bisa pasang sekarang?`, pl: `Czy można założyć teraz?`, ipa: `bi-sa pa-sang sə-ka-rang`},{id: `Nomor saya aktif?`, pl: `Czy mój numer jest aktywny?`, ipa: `no-mor sa-ja ak-tif`},{id: `Saya mau isi ulang.`, pl: `Chcę doładować.`, ipa: `sa-ja ma-u i-si u-lang`},{id: `Saya mau kirim kartu pos.`, pl: `Chcę wysłać pocztówkę.`, ipa: `sa-ja ma-u ki-rim kar-tu pos`}], grammar: `„Beli” oznacza „kupić”, a „pesan” częściej „zamówić” lub „zarezerwować”. „Isi ulang” dosłownie znaczy „napełnić ponownie”, ale w praktyce oznacza doładowanie telefonu. W punktach usługowych mów krótko: „Saya mau beli...” albo „Saya mau isi ulang”.`, practice: [`Powiedz, że chcesz kupić kartę SIM.`,`Zapytaj o pakiet danych.`,`Zapytaj, czy można założyć kartę teraz.`,`Powiedz, że chcesz doładować telefon.`,`Powiedz, że chcesz wysłać pocztówkę.`]},{day: 27, title: `Pieniądze, bankomat i płatności`, title_native: `Uang, ATM, dan pembayaran`, focus: `Dziś nauczysz się słów potrzebnych przy bankomacie, w kantorze i podczas płacenia. Przyda się to w miastach i mniejszych miejscowościach, gdzie gotówka bywa ważna.`, vocab: [{id: `ATM`, pl: `bankomat`, ipa: `a-te-em`},{id: `bank`, pl: `bank`, ipa: `bank`},{id: `kartu kredit`, pl: `karta kredytowa`, ipa: `kar-tu kre-dit`},{id: `kartu debit`, pl: `karta debetowa`, ipa: `kar-tu de-bit`},{id: `tunai`, pl: `gotówka`, ipa: `tu-naj`},{id: `kembalian`, pl: `reszta`, ipa: `kəm-ba-li-an`},{id: `struk`, pl: `paragon`, ipa: `struk`},{id: `tarik uang`, pl: `wypłacić pieniądze`, ipa: `ta-rik u-ang`},{id: `tukar uang`, pl: `wymienić pieniądze`, ipa: `tu-kar u-ang`},{id: `biaya`, pl: `opłata`, ipa: `bi-a-ja`}], phrases: [{id: `Di mana ATM?`, pl: `Gdzie jest bankomat?`, ipa: `di ma-na a-te-em`},{id: `Saya mau tarik uang.`, pl: `Chcę wypłacić pieniądze.`, ipa: `sa-ja ma-u ta-rik u-ang`},{id: `Bisa bayar dengan kartu?`, pl: `Czy można zapłacić kartą?`, ipa: `bi-sa ba-jar də-ngan kar-tu`},{id: `Saya bayar tunai.`, pl: `Płacę gotówką.`, ipa: `sa-ja ba-jar tu-naj`},{id: `Ada biaya tambahan?`, pl: `Czy jest dodatkowa opłata?`, ipa: `a-da bi-a-ja tam-ba-han`},{id: `Minta struk, tolong.`, pl: `Poproszę paragon.`, ipa: `min-ta struk, to-long`}], grammar: `„Bayar” oznacza „płacić”, a „dengan” oznacza „z / za pomocą”. „Bayar dengan kartu” to dosłownie „płacić za pomocą karty”. „Tambahan” oznacza „dodatkowy”, więc „biaya tambahan” to dodatkowa opłata.`, practice: [`Zapytaj, gdzie jest bankomat.`,`Powiedz, że chcesz wypłacić pieniądze.`,`Zapytaj, czy można zapłacić kartą.`,`Zapytaj o dodatkową opłatę.`,`Poproś o paragon.`]},{day: 28, title: `Zaproszenia i uprzejme odmowy`, title_native: `Undangan dan penolakan sopan`, focus: `Nauczysz się przyjmować i odmawiać propozycje w naturalny sposób. Przyda się to przy zaproszeniach na jedzenie, transport, zakupy lub wspólne zwiedzanie.`, vocab: [{id: `mau`, pl: `chcieć`, ipa: `ma-u`},{id: `ingin`, pl: `chcieć bardziej formalnie`, ipa: `ing-in`},{id: `boleh`, pl: `móc / wolno`, ipa: `bo-leh`},{id: `mungkin`, pl: `może`, ipa: `mung-kin`},{id: `maaf`, pl: `przepraszam`, ipa: `ma-af`},{id: `sibuk`, pl: `zajęty`, ipa: `si-buk`},{id: `capek`, pl: `zmęczony`, ipa: `cza-pek`},{id: `setuju`, pl: `zgadzać się`, ipa: `sə-tu-dżu`},{id: `nanti saja`, pl: `może później`, ipa: `nan-ti sa-dża`},{id: `tidak apa-apa`, pl: `nic nie szkodzi`, ipa: `ti-dak a-pa a-pa`}], phrases: [{id: `Mau ikut?`, pl: `Chcesz iść z nami?`, ipa: `ma-u i-kut`},{id: `Ya, saya mau.`, pl: `Tak, chcę.`, ipa: `ja, sa-ja ma-u`},{id: `Maaf, saya tidak bisa.`, pl: `Przepraszam, nie mogę.`, ipa: `ma-af, sa-ja ti-dak bi-sa`},{id: `Mungkin nanti.`, pl: `Może później.`, ipa: `mung-kin nan-ti`},{id: `Saya capek hari ini.`, pl: `Jestem dzisiaj zmęczony/zmęczona.`, ipa: `sa-ja cza-pek ha-ri i-ni`},{id: `Tidak apa-apa.`, pl: `Nic nie szkodzi.`, ipa: `ti-dak a-pa a-pa`}], grammar: `„Mau” jest bardzo częste w mowie i oznacza „chcieć”. „Ingin” jest trochę bardziej formalne lub staranne. W codziennych rozmowach „Saya mau” jest zupełnie naturalne, a „Saya tidak bisa” to uprzejma odmowa.`, practice: [`Przyjmij zaproszenie prostym zdaniem.`,`Odmów uprzejmie, mówiąc, że nie możesz.`,`Powiedz, że może później.`,`Powiedz, że jesteś dziś zmęczony lub zmęczona.`,`Przećwicz odpowiedź „Tidak apa-apa”.`]},{day: 29, title: `Lokalne zwyczaje i kultura`, title_native: `Kebiasaan lokal dan budaya`, focus: `Dziś nauczysz się zwrotów, które pomagają zachować uprzejmość w domach, świątyniach i miejscach publicznych w Indonezji. Skupimy się na pytaniu o zasady i okazywaniu szacunku.`, vocab: [{id: `budaya`, pl: `kultura`, ipa: `bu-da-ja`},{id: `adat`, pl: `zwyczaj`, ipa: `a-dat`},{id: `sopan`, pl: `uprzejmy`, ipa: `so-pan`},{id: `hormat`, pl: `szacunek`, ipa: `hor-mat`},{id: `sepatu`, pl: `buty`, ipa: `sə-pa-tu`},{id: `masuk`, pl: `wejść`, ipa: `ma-suk`},{id: `keluar`, pl: `wyjść`, ipa: `kə-lu-ar`},{id: `boleh`, pl: `wolno / można`, ipa: `bo-leh`},{id: `dilarang`, pl: `zabronione`, ipa: `di-la-rang`},{id: `pakaian`, pl: `ubranie`, ipa: `pa-ka-jan`}], phrases: [{id: `Boleh masuk?`, pl: `Czy można wejść?`, ipa: `bo-leh ma-suk`},{id: `Harus lepas sepatu?`, pl: `Czy trzeba zdjąć buty?`, ipa: `ha-rus lə-pas sə-pa-tu`},{id: `Foto dilarang?`, pl: `Czy zdjęcia są zabronione?`, ipa: `fo-to di-la-rang`},{id: `Saya mau sopan.`, pl: `Chcę być uprzejmy/uprzejma.`, ipa: `sa-ja ma-u so-pan`},{id: `Apa aturannya?`, pl: `Jakie są zasady?`, ipa: `a-pa a-tu-ran-nja`},{id: `Terima kasih atas bantuannya.`, pl: `Dziękuję za pomoc.`, ipa: `tə-ri-ma ka-sih a-tas ban-tu-an-nja`}], grammar: `„Harus” oznacza „musieć”, a „dilarang” oznacza „zabronione”. W miejscach religijnych i tradycyjnych pytania z „boleh” i „harus” brzmią bardzo taktownie. „Aturan” oznacza „zasada”, a „aturannya” — „zasady tutaj / te zasady”.`, practice: [`Zapytaj, czy można wejść.`,`Zapytaj, czy trzeba zdjąć buty.`,`Zapytaj, czy zdjęcia są zabronione.`,`Powiedz, że chcesz być uprzejmy lub uprzejma.`,`Podziękuj za pomoc bardziej pełnym zdaniem.`]},{day: 30, title: `Powtórka podróżna i pewność w rozmowie`, title_native: `Ulangan perjalanan dan percaya diri berbicara`, focus: `Ostatni dzień łączy najważniejsze sytuacje: hotel, jedzenie, transport, zakupy i pomoc. Nauczysz się budować krótkie, elastyczne zdania, które działają w prawdziwej podróży po Indonezji.`, vocab: [{id: `perjalanan`, pl: `podróż`, ipa: `pər-dża-la-nan`},{id: `pengalaman`, pl: `doświadczenie`, ipa: `pə-nga-la-man`},{id: `mudah`, pl: `łatwy`, ipa: `mu-dah`},{id: `sulit`, pl: `trudny`, ipa: `su-lit`},{id: `penting`, pl: `ważny`, ipa: `pən-ting`},{id: `cukup`, pl: `wystarczająco`, ipa: `czu-kup`},{id: `kurang`, pl: `za mało / brak`, ipa: `ku-rang`},{id: `lebih`, pl: `bardziej / więcej`, ipa: `lə-bih`},{id: `semua`, pl: `wszystko / wszyscy`, ipa: `sə-mu-a`},{id: `selesai`, pl: `skończone`, ipa: `sə-lə-saj`}], phrases: [{id: `Saya belajar bahasa Indonesia.`, pl: `Uczę się indonezyjskiego.`, ipa: `sa-ja bə-la-dżar ba-ha-sa in-do-ne-sja`},{id: `Tolong bicara pelan-pelan.`, pl: `Proszę mówić powoli.`, ipa: `to-long bi-cza-ra pə-lan pə-lan`},{id: `Saya kurang mengerti.`, pl: `Nie do końca rozumiem.`, ipa: `sa-ja ku-rang mə-ngər-ti`},{id: `Bisa ulangi?`, pl: `Czy może pan/pani powtórzyć?`, ipa: `bi-sa u-lang-i`},{id: `Ini pengalaman bagus.`, pl: `To dobre doświadczenie.`, ipa: `i-ni pə-nga-la-man ba-gus`},{id: `Terima kasih, semuanya selesai.`, pl: `Dziękuję, wszystko załatwione.`, ipa: `tə-ri-ma ka-sih, sə-mu-a sə-lə-saj`}], grammar: `Na koniec zapamiętaj strategię: krótkie zdania są lepsze niż skomplikowane. „Saya mau...”, „Saya perlu...”, „Di mana...?”, „Berapa...?” i „Bisa...?” wystarczą w wielu realnych sytuacjach. Jeśli nie rozumiesz, powiedz „Tolong bicara pelan-pelan” albo „Bisa ulangi?”.`, practice: [`Powiedz, że uczysz się indonezyjskiego.`,`Poproś, żeby ktoś mówił powoli.`,`Powiedz, że nie do końca rozumiesz.`,`Poproś o powtórzenie.`,`Stwórz mini-dialog łączący hotel, transport i jedzenie.`]}];

var CONVERSATIONS_PL_ID = [{id: 1, title: `Zamawianie w kawiarni`, scene: `Jesteś w małej kawiarni w Ubudzie na Bali. Chcesz zamówić kawę i coś słodkiego, ale bez cukru w napoju.`, lines: [{who: `them`, id: `Selamat pagi, mau pesan apa?`, pl: `Dzień dobry, co chce pan/pani zamówić?`},{who: `you`, id: `Selamat pagi, saya mau kopi panas.`, pl: `Dzień dobry, chcę gorącą kawę.`},{who: `them`, id: `Dengan gula?`, pl: `Z cukrem?`},{who: `you`, id: `Tanpa gula, tolong.`, pl: `Bez cukru, proszę.`},{who: `them`, id: `Mau susu?`, pl: `Chce pan/pani mleko?`},{who: `you`, id: `Ya, dengan susu sedikit.`, pl: `Tak, z odrobiną mleka.`},{who: `them`, id: `Mau kue juga?`, pl: `Chce pan/pani też ciastko?`},{who: `you`, id: `Ya, satu kue ini.`, pl: `Tak, jedno to ciastko.`},{who: `them`, id: `Untuk di sini atau dibawa pulang?`, pl: `Na miejscu czy na wynos?`},{who: `you`, id: `Untuk di sini.`, pl: `Na miejscu.`},{who: `them`, id: `Baik, semuanya dua puluh lima ribu.`, pl: `Dobrze, wszystko razem dwadzieścia pięć tysięcy.`},{who: `you`, id: `Terima kasih.`, pl: `Dziękuję.`}]},{id: 2, title: `Zameldowanie w hotelu`, scene: `Przyjeżdżasz wieczorem do hotelu w Dżakarcie. Masz rezerwację i chcesz zapytać o śniadanie oraz godzinę wymeldowania.`, lines: [{who: `them`, id: `Selamat malam, ada reservasi?`, pl: `Dobry wieczór, czy jest rezerwacja?`},{who: `you`, id: `Selamat malam, saya punya reservasi.`, pl: `Dobry wieczór, mam rezerwację.`},{who: `them`, id: `Atas nama siapa?`, pl: `Na jakie nazwisko?`},{who: `you`, id: `Atas nama Anna Kowalska.`, pl: `Na nazwisko Anna Kowalska.`},{who: `them`, id: `Boleh lihat paspor?`, pl: `Czy mogę zobaczyć paszport?`},{who: `you`, id: `Ya, ini paspor saya.`, pl: `Tak, oto mój paszport.`},{who: `them`, id: `Kamar Anda di lantai tiga.`, pl: `Pana/Pani pokój jest na trzecim piętrze.`},{who: `you`, id: `Apakah sarapan termasuk?`, pl: `Czy śniadanie jest wliczone?`},{who: `them`, id: `Ya, sarapan mulai jam tujuh pagi.`, pl: `Tak, śniadanie zaczyna się o siódmej rano.`},{who: `you`, id: `Jam berapa check-out?`, pl: `O której jest wymeldowanie?`},{who: `them`, id: `Check-out jam dua belas siang.`, pl: `Wymeldowanie jest o dwunastej w południe.`},{who: `you`, id: `Terima kasih atas bantuannya.`, pl: `Dziękuję za pomoc.`}]},{id: 3, title: `Pytanie o drogę`, scene: `Spacerujesz po Yogyakarcie i chcesz dojść do muzeum. Zatrzymujesz lokalną osobę i prosisz o prostą wskazówkę.`, lines: [{who: `you`, id: `Permisi, boleh tanya?`, pl: `Przepraszam, czy mogę zapytać?`},{who: `them`, id: `Ya, silakan.`, pl: `Tak, proszę.`},{who: `you`, id: `Di mana museum ini?`, pl: `Gdzie jest to muzeum?`},{who: `them`, id: `Jalan lurus, lalu belok kiri.`, pl: `Proszę iść prosto, potem skręcić w lewo.`},{who: `you`, id: `Apakah jauh?`, pl: `Czy to daleko?`},{who: `them`, id: `Tidak jauh, sekitar lima menit.`, pl: `Nie daleko, około pięciu minut.`},{who: `you`, id: `Setelah belok kiri, ke mana?`, pl: `Po skręcie w lewo dokąd?`},{who: `them`, id: `Museum ada di kanan jalan.`, pl: `Muzeum jest po prawej stronie ulicy.`},{who: `you`, id: `Baik, terima kasih.`, pl: `Dobrze, dziękuję.`},{who: `them`, id: `Sama-sama.`, pl: `Nie ma za co.`}]},{id: 4, title: `W restauracji`, scene: `Jesteś w lokalnym warungu w Surabai. Chcesz zamówić jedzenie, ale nie możesz jeść bardzo ostrych potraw.`, lines: [{who: `them`, id: `Selamat siang, mau makan apa?`, pl: `Dzień dobry, co chce pan/pani zjeść?`},{who: `you`, id: `Boleh lihat menu?`, pl: `Czy mogę zobaczyć menu?`},{who: `them`, id: `Silakan, ini menunya.`, pl: `Proszę, oto menu.`},{who: `you`, id: `Saya mau nasi goreng ayam.`, pl: `Chcę smażony ryż z kurczakiem.`},{who: `them`, id: `Mau pedas?`, pl: `Ma być ostre?`},{who: `you`, id: `Tidak pedas, tolong.`, pl: `Nieostre, proszę.`},{who: `them`, id: `Minumnya apa?`, pl: `Co do picia?`},{who: `you`, id: `Air dingin tanpa es.`, pl: `Zimną wodę bez lodu.`},{who: `them`, id: `Baik, tunggu sebentar.`, pl: `Dobrze, proszę chwilę poczekać.`},{who: `you`, id: `Terima kasih.`, pl: `Dziękuję.`},{who: `them`, id: `Ini pesanannya.`, pl: `Oto zamówienie.`},{who: `you`, id: `Kelihatannya enak sekali.`, pl: `Wygląda bardzo smacznie.`}]},{id: 5, title: `Kupowanie biletu na transport`, scene: `Jesteś na stacji w Bandung i chcesz kupić bilet kolejowy. Pytasz o cenę, godzinę i peron.`, lines: [{who: `them`, id: `Selamat pagi, mau ke mana?`, pl: `Dzień dobry, dokąd chce pan/pani jechać?`},{who: `you`, id: `Saya mau ke Jakarta.`, pl: `Chcę jechać do Dżakarty.`},{who: `them`, id: `Mau tiket jam berapa?`, pl: `Na którą godzinę chce pan/pani bilet?`},{who: `you`, id: `Jam sepuluh pagi, kalau ada.`, pl: `Na dziesiątą rano, jeśli jest.`},{who: `them`, id: `Ada, satu tiket?`, pl: `Jest, jeden bilet?`},{who: `you`, id: `Ya, satu tiket.`, pl: `Tak, jeden bilet.`},{who: `them`, id: `Harganya seratus lima puluh ribu.`, pl: `Cena to sto pięćdziesiąt tysięcy.`},{who: `you`, id: `Bisa bayar dengan kartu?`, pl: `Czy można zapłacić kartą?`},{who: `them`, id: `Bisa.`, pl: `Można.`},{who: `you`, id: `Kereta dari peron berapa?`, pl: `Z którego peronu jest pociąg?`},{who: `them`, id: `Dari peron dua.`, pl: `Z peronu drugiego.`},{who: `you`, id: `Terima kasih banyak.`, pl: `Bardzo dziękuję.`}]},{id: 6, title: `Zakupy na targu`, scene: `Jesteś na targu w Ubudzie i oglądasz torby oraz pamiątki. Chcesz zapytać o cenę i spróbować uprzejmie negocjować.`, lines: [{who: `them`, id: `Halo, silakan lihat-lihat.`, pl: `Cześć, proszę się rozejrzeć.`},{who: `you`, id: `Terima kasih, saya hanya lihat-lihat.`, pl: `Dziękuję, tylko się rozglądam.`},{who: `them`, id: `Tas ini bagus.`, pl: `Ta torba jest ładna.`},{who: `you`, id: `Berapa harga tas ini?`, pl: `Ile kosztuje ta torba?`},{who: `them`, id: `Seratus ribu.`, pl: `Sto tysięcy.`},{who: `you`, id: `Bisa lebih murah?`, pl: `Czy może być taniej?`},{who: `them`, id: `Bisa, delapan puluh ribu.`, pl: `Może, osiemdziesiąt tysięcy.`},{who: `you`, id: `Tujuh puluh ribu bisa?`, pl: `Czy siedemdziesiąt tysięcy może być?`},{who: `them`, id: `Baik, tujuh puluh ribu.`, pl: `Dobrze, siedemdziesiąt tysięcy.`},{who: `you`, id: `Saya beli ini.`, pl: `Kupuję to.`},{who: `them`, id: `Terima kasih.`, pl: `Dziękuję.`},{who: `you`, id: `Sama-sama.`, pl: `Nie ma za co.`}]},{id: 7, title: `W aptece`, scene: `Źle się czujesz po całym dniu w upale w Denpasar. Wchodzisz do apteki i chcesz kupić coś na ból głowy oraz wodę mineralną.`, lines: [{who: `them`, id: `Selamat sore, perlu apa?`, pl: `Dzień dobry, czego pan/pani potrzebuje?`},{who: `you`, id: `Kepala saya sakit.`, pl: `Boli mnie głowa.`},{who: `them`, id: `Ada demam?`, pl: `Czy jest gorączka?`},{who: `you`, id: `Tidak, hanya sakit kepala.`, pl: `Nie, tylko ból głowy.`},{who: `them`, id: `Ini obat untuk sakit kepala.`, pl: `To lekarstwo na ból głowy.`},{who: `you`, id: `Bagaimana cara minumnya?`, pl: `Jak to zażywać?`},{who: `them`, id: `Minum satu tablet setelah makan.`, pl: `Proszę wziąć jedną tabletkę po jedzeniu.`},{who: `you`, id: `Saya juga perlu air mineral.`, pl: `Potrzebuję też wody mineralnej.`},{who: `them`, id: `Ada di sebelah kanan.`, pl: `Jest po prawej stronie.`},{who: `you`, id: `Berapa semuanya?`, pl: `Ile wszystko razem?`},{who: `them`, id: `Tiga puluh ribu.`, pl: `Trzydzieści tysięcy.`},{who: `you`, id: `Terima kasih.`, pl: `Dziękuję.`}]},{id: 8, title: `Mała rozmowa z lokalną osobą`, scene: `Siedzisz w pociągu z Yogyakarty do Dżakarty. Osoba obok zaczyna uprzejmą rozmowę, a ty odpowiadasz prostym indonezyjskim.`, lines: [{who: `them`, id: `Halo, dari mana?`, pl: `Cześć, skąd jesteś?`},{who: `you`, id: `Halo, saya dari Polandia.`, pl: `Cześć, jestem z Polski.`},{who: `them`, id: `Wah, jauh sekali.`, pl: `Wow, bardzo daleko.`},{who: `you`, id: `Ya, saya sedang liburan di Indonesia.`, pl: `Tak, jestem na wakacjach w Indonezji.`},{who: `them`, id: `Suka Indonesia?`, pl: `Lubisz Indonezję?`},{who: `you`, id: `Ya, saya suka Indonesia.`, pl: `Tak, lubię Indonezję.`},{who: `them`, id: `Sudah ke Bali?`, pl: `Byłeś/Byłaś już na Bali?`},{who: `you`, id: `Sudah, Bali indah sekali.`, pl: `Tak, Bali jest bardzo piękna.`},{who: `them`, id: `Bisa bahasa Indonesia sedikit?`, pl: `Mówisz trochę po indonezyjsku?`},{who: `you`, id: `Sedikit, saya masih belajar.`, pl: `Trochę, wciąż się uczę.`},{who: `them`, id: `Bagus, selamat jalan.`, pl: `Świetnie, dobrej podróży.`},{who: `you`, id: `Terima kasih, senang bertemu Anda.`, pl: `Dziękuję, miło pana/panią poznać.`}]}];